import{_ as s,n as d,p as o,q as i,s as n,R as t,t as a,Z as c}from"./framework-fdd38eac.js";const r={},l=c(`<h2 id="前言" tabindex="-1"><a class="header-anchor" href="#前言" aria-hidden="true">#</a> 前言</h2><p>Mongoose 是 Node.js 生态中最流行的 MongoDB ODM（Object-Document Mapping）库。很多同学在使用 Mongoose 时可能会有疑问：Mongoose 到底是怎么工作的？它和原生 MongoDB 命令是什么关系？今天我们就来深度解析 Mongoose 的实现原理。</p><h2 id="一、mongoose-是-封装层" tabindex="-1"><a class="header-anchor" href="#一、mongoose-是-封装层" aria-hidden="true">#</a> 一、Mongoose 是 &quot;封装层&quot;</h2><h3 id="_1-1-什么是封装层" tabindex="-1"><a class="header-anchor" href="#_1-1-什么是封装层" aria-hidden="true">#</a> 1.1 什么是封装层</h3><p>Mongoose 本质上是一个 <strong>封装层（Wrapper Layer）</strong>，它位于应用代码和 MongoDB 数据库之间：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>应用代码 → Mongoose → MongoDB Driver → MongoDB 数据库
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Mongoose 并不改变 MongoDB 的核心行为，它只是在 API 层面做了更友好的封装，让开发者可以用面向对象的方式操作数据库。</p><h3 id="_1-2-封装了什么" tabindex="-1"><a class="header-anchor" href="#_1-2-封装了什么" aria-hidden="true">#</a> 1.2 封装了什么</h3><table><thead><tr><th>原始操作</th><th>Mongoose 封装</th></tr></thead><tbody><tr><td>写原生 MongoDB 命令</td><td>链式调用的 API 方法</td></tr><tr><td>手动验证数据</td><td>Schema + Middleware 自动验证</td></tr><tr><td>处理数据库连接</td><td>连接池 + 自动重连</td></tr><tr><td>处理数据类型转换</td><td>TypeScript/ES6 Class 支持</td></tr></tbody></table><h3 id="_1-3-为什么需要封装层" tabindex="-1"><a class="header-anchor" href="#_1-3-为什么需要封装层" aria-hidden="true">#</a> 1.3 为什么需要封装层</h3><p>原生 MongoDB Driver 已经很好用了，但存在以下问题：</p><ol><li><strong>数据规范性</strong>：没有 Schema 定义，数据结构随意</li><li><strong>开发体验</strong>：API 较为底层，查询语法不够直观</li><li><strong>业务逻辑</strong>：缺少钩子函数，事务处理不够方便</li><li><strong>类型安全</strong>：原生 Driver 类型支持不够完善</li></ol><p>Mongoose 解决了这些问题，但同时也带来了额外的开销。理解它的实现原理，可以帮助我们更好地使用它，甚至在必要时选择绕过它。</p><h2 id="二、mongoose-执行流程拆解" tabindex="-1"><a class="header-anchor" href="#二、mongoose-执行流程拆解" aria-hidden="true">#</a> 二、Mongoose 执行流程拆解</h2><h3 id="_2-1-整体架构" tabindex="-1"><a class="header-anchor" href="#_2-1-整体架构" aria-hidden="true">#</a> 2.1 整体架构</h3><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>┌─────────────────────────────────────────────────────────────┐
│                      Application Code                        │
│         UserModel.find(), user.save(), etc.                │
└─────────────────────────┬───────────────────────────────────┘
                          │
                          ▼
┌─────────────────────────────────────────────────────────────┐
│                        Mongoose Core                        │
│  ┌─────────────┐  ┌─────────────┐  ┌─────────────────────┐  │
│  │   Schema    │  │   Model     │  │     Document        │  │
│  │  (定义结构)  │→ │  (构造函数)  │→ │   (实例对象)         │  │
│  └─────────────┘  └─────────────┘  └─────────────────────┘  │
│         │                │                    │             │
│         └────────────────┼────────────────────┘             │
│                          ▼                                   │
│  ┌─────────────────────────────────────────────────────────┐ │
│  │                    Query/Collection                     │ │
│  │              (查询构建器 + 操作代理)                      │ │
│  └─────────────────────────┬───────────────────────────────┘ │
└────────────────────────────┼────────────────────────────────┘
                             │
                             ▼
┌─────────────────────────────────────────────────────────────┐
│                     MongoDB Driver                           │
│              (mongodb 包，真正的数据库操作)                     │
└────────────────────────────┼────────────────────────────────┘
                             │
                             ▼
┌─────────────────────────────────────────────────────────────┐
│                      MongoDB Server                          │
└─────────────────────────────────────────────────────────────┘
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-2-执行流程详解" tabindex="-1"><a class="header-anchor" href="#_2-2-执行流程详解" aria-hidden="true">#</a> 2.2 执行流程详解</h3><p>以 <code>User.find({ name: &#39;zhaoyifan&#39; })</code> 为例：</p><h4 id="第一步-定义-schema-启动时" tabindex="-1"><a class="header-anchor" href="#第一步-定义-schema-启动时" aria-hidden="true">#</a> 第一步：定义 Schema（启动时）</h4><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> userSchema <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">mongoose<span class="token punctuation">.</span>Schema</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
  <span class="token literal-property property">name</span><span class="token operator">:</span> String<span class="token punctuation">,</span>
  <span class="token literal-property property">age</span><span class="token operator">:</span> Number<span class="token punctuation">,</span>
  <span class="token literal-property property">email</span><span class="token operator">:</span> String
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Mongoose 会在内存中构建一个 <code>Schema</code> 对象，解析每个字段的类型、默认值、验证器等。</p><p><strong>对应内部操作</strong>：</p><ul><li>遍历 schema 定义，转换为内部格式</li><li>注册验证器（validators）</li><li>注册 middleware 钩子</li></ul><h4 id="第二步-创建-model-启动时" tabindex="-1"><a class="header-anchor" href="#第二步-创建-model-启动时" aria-hidden="true">#</a> 第二步：创建 Model（启动时）</h4><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> User <span class="token operator">=</span> mongoose<span class="token punctuation">.</span><span class="token function">model</span><span class="token punctuation">(</span><span class="token string">&#39;User&#39;</span><span class="token punctuation">,</span> userSchema<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Mongoose 会：</p><ol><li>根据 model name 生成 collection name（<code>users</code>）</li><li>创建 Query 类和 Document 类的子类</li><li>注册到 Mongoose 的 models 缓存中</li></ol><p><strong>对应内部操作</strong>：</p><ul><li><code>db.createCollection(&#39;users&#39;)</code> 延迟到第一次操作时</li><li>生成唯一索引（<code>_id</code>）</li></ul><h4 id="第三步-执行查询-运行时" tabindex="-1"><a class="header-anchor" href="#第三步-执行查询-运行时" aria-hidden="true">#</a> 第三步：执行查询（运行时）</h4><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> result <span class="token operator">=</span> <span class="token keyword">await</span> User<span class="token punctuation">.</span><span class="token function">find</span><span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&#39;zhaoyifan&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>完整执行流程</strong>：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>User.find({ name: &#39;zhaoyifan&#39; })
    │
┌──────────────────────────────────────┐
│                                     │
│  Query.find()                        │
│  - 解析 query 对象                    │
│  - 应用 schema 的投影（select）       │
│  - 附加默认选项                       │
└─────────────────┬────────────────────┘
                  │
                  ▼
┌──────────────────────────────────────┐
│  Query.exec() / toJSON()             │
│  - 转换为 MongoDB Driver 可执行的格式   │
│  - 合并 options                       │
└─────────────────┬────────────────────┘
                  │
                  ▼
┌──────────────────────────────────────┐
│  Model.collection.find()             │
│  - 调用 MongoDB Driver 的 find 方法    │
│  - 发送 OP_QUERY 或 opMsg 命令         │
└─────────────────┬────────────────────┘
                  │
                  ▼
┌──────────────────────────────────────┐
│  MongoDB Server                      │
│  - 执行 find 命令                     │
│  - 返回 cursor                        │
└─────────────────┬────────────────────┘
                  │
                  ▼
┌──────────────────────────────────────┐
│  Mongoose 转换结果                    │
│  - 遍历 cursor                       │
│  - 将普通对象转换为 Document 实例     │
│  - 应用 schema 的 getter/setter      │
│  - 触发 &#39;init&#39; middleware            │
└──────────────────────────────────────┘
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-3-关键转换点" tabindex="-1"><a class="header-anchor" href="#_2-3-关键转换点" aria-hidden="true">#</a> 2.3 关键转换点</h3><table><thead><tr><th>阶段</th><th>转换内容</th></tr></thead><tbody><tr><td>Schema 定义 → Model</td><td>类型解析、验证器注册</td></tr><tr><td>查询参数 → MongoDB 命令</td><td>query casting（将字符串 ObjectId 转成 ObjectId 对象）</td></tr><tr><td>查询结果 → Document</td><td>实例化、getter/setter 应用</td></tr><tr><td>Document → JSON</td><td>getter/virtual/transform 应用</td></tr></tbody></table><h3 id="_2-4-核心代码路径" tabindex="-1"><a class="header-anchor" href="#_2-4-核心代码路径" aria-hidden="true">#</a> 2.4 核心代码路径</h3><p>Mongoose 的核心代码在 <code>lib/</code> 目录下：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>lib/
├── schema/        # Schema 定义和验证
├── model/         # Model 创建
├── document/     # Document 类
├── query/        # 查询构建器
├── connection/   # 数据库连接
├── drivers/      # MongoDB Driver 适配层
└── index.js      # 入口文件
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>关键转换发生在 <code>lib/query.js</code> 和 <code>lib/model.js</code> 中。</p><h2 id="三、方法-mongodb-命令映射表" tabindex="-1"><a class="header-anchor" href="#三、方法-mongodb-命令映射表" aria-hidden="true">#</a> 三、方法 - MongoDB 命令映射表</h2><h3 id="_3-1-查找操作" tabindex="-1"><a class="header-anchor" href="#_3-1-查找操作" aria-hidden="true">#</a> 3.1 查找操作</h3><table><thead><tr><th>Mongoose 方法</th><th>MongoDB 命令</th><th>说明</th></tr></thead><tbody><tr><td><code>Model.find(query, projection, options)</code></td><td><code>find</code></td><td>查询多个文档</td></tr><tr><td><code>Model.findOne(query, projection, options)</code></td><td><code>find</code> + <code>limit(1)</code></td><td>查询单个文档</td></tr><tr><td><code>Model.findById(id, projection, options)</code></td><td><code>find</code> + <code>_id: ObjectId(id)</code></td><td>根据 ID 查询</td></tr><tr><td><code>Model.findOneAndUpdate(filter, update, options)</code></td><td><code>findAndModify</code> / <code>findOneAndUpdate</code></td><td>查询并更新</td></tr><tr><td><code>Model.findOneAndDelete(filter, options)</code></td><td><code>findAndModify</code> / <code>findOneAndDelete</code></td><td>查询并删除</td></tr><tr><td><code>Model.findOneAndReplace(filter, replacement, options)</code></td><td><code>findOneAndReplace</code></td><td>查询并替换</td></tr><tr><td><code>Model.countDocuments(filter, options)</code></td><td><code>count</code> / <code>countDocuments</code></td><td>统计文档数量</td></tr><tr><td><code>Model.estimatedDocumentCount(options)</code></td><td><code>count</code></td><td>估算文档数量（更快）</td></tr><tr><td><code>Model.distinct(field, filter)</code></td><td><code>distinct</code></td><td>获取字段的唯一值</td></tr></tbody></table><h3 id="_3-2-创建操作" tabindex="-1"><a class="header-anchor" href="#_3-2-创建操作" aria-hidden="true">#</a> 3.2 创建操作</h3><table><thead><tr><th>Mongoose 方法</th><th>MongoDB 命令</th><th>说明</th></tr></thead><tbody><tr><td><code>Doc.save()</code></td><td><code>insert</code> / <code>insertOne</code></td><td>保存文档（新增或更新）</td></tr><tr><td><code>Model.create(doc)</code></td><td><code>insert</code> / <code>insertOne</code></td><td>批量创建</td></tr><tr><td><code>Model.insertMany(docs)</code></td><td><code>insert</code> / <code>insertMany</code></td><td>批量插入</td></tr><tr><td><code>Model.bulkWrite(operations)</code></td><td><code>bulkWrite</code></td><td>批量操作</td></tr></tbody></table><h3 id="_3-3-更新操作" tabindex="-1"><a class="header-anchor" href="#_3-3-更新操作" aria-hidden="true">#</a> 3.3 更新操作</h3><table><thead><tr><th>Mongoose 方法</th><th>MongoDB 命令</th><th>说明</th></tr></thead><tbody><tr><td><code>Model.updateOne(filter, update, options)</code></td><td><code>update</code> / <code>updateOne</code></td><td>更新单个文档</td></tr><tr><td><code>Model.updateMany(filter, update, options)</code></td><td><code>update</code> / <code>updateMany</code></td><td>更新多个文档</td></tr><tr><td><code>Doc.updateOne(update, options)</code></td><td><code>update</code> / <code>updateOne</code></td><td>实例方法更新</td></tr><tr><td><code>Model.findOneAndUpdate(filter, update, options)</code></td><td><code>findAndModify</code></td><td>查询并更新</td></tr><tr><td><code>Model.replaceOne(filter, replacement, options)</code></td><td><code>replaceOne</code></td><td>替换单个文档</td></tr></tbody></table><h3 id="_3-4-删除操作" tabindex="-1"><a class="header-anchor" href="#_3-4-删除操作" aria-hidden="true">#</a> 3.4 删除操作</h3><table><thead><tr><th>Mongoose 方法</th><th>MongoDB 命令</th><th>说明</th></tr></thead><tbody><tr><td><code>Model.deleteOne(filter, options)</code></td><td><code>delete</code> / <code>deleteOne</code></td><td>删除单个文档</td></tr><tr><td><code>Model.deleteMany(filter, options)</code></td><td><code>delete</code> / <code>deleteMany</code></td><td>删除多个文档</td></tr><tr><td><code>Model.findOneAndDelete(filter, options)</code></td><td><code>findAndModify</code></td><td>查询并删除</td></tr></tbody></table><h3 id="_3-5-聚合操作" tabindex="-1"><a class="header-anchor" href="#_3-5-聚合操作" aria-hidden="true">#</a> 3.5 聚合操作</h3><table><thead><tr><th>Mongoose 方法</th><th>MongoDB 命令</th><th>说明</th></tr></thead><tbody><tr><td><code>Model.aggregate(pipeline)</code></td><td><code>aggregate</code></td><td>聚合管道</td></tr><tr><td><code>Model.watch(pipeline)</code></td><td><code>changeStream</code></td><td>变更流监听</td></tr></tbody></table><h3 id="_3-6-索引操作" tabindex="-1"><a class="header-anchor" href="#_3-6-索引操作" aria-hidden="true">#</a> 3.6 索引操作</h3><table><thead><tr><th>Mongoose 方法</th><th>MongoDB 命令</th><th>说明</th></tr></thead><tbody><tr><td><code>Model.createIndex(fields, options)</code></td><td><code>createIndexes</code></td><td>创建索引</td></tr><tr><td><code>Model.indexes()</code></td><td><code>listIndexes</code></td><td>获取索引列表</td></tr><tr><td><code>Model.dropIndex(indexName)</code></td><td><code>dropIndex</code></td><td>删除索引</td></tr><tr><td><code>Model.dropIndexes()</code></td><td><code>dropIndexes</code></td><td>删除所有索引</td></tr></tbody></table><h3 id="_3-7-连接操作" tabindex="-1"><a class="header-anchor" href="#_3-7-连接操作" aria-hidden="true">#</a> 3.7 连接操作</h3><table><thead><tr><th>Mongoose 方法</th><th>MongoDB 命令</th><th>说明</th></tr></thead><tbody><tr><td><code>mongoose.connect(uri, options)</code></td><td><code>isMaster</code> / <code>hello</code></td><td>建立连接</td></tr><tr><td><code>connection.close(force)</code></td><td><code>killCursors</code></td><td>关闭连接</td></tr><tr><td><code>connection.db</code></td><td>-</td><td>获取原生数据库对象</td></tr></tbody></table><h3 id="_3-8-事务操作" tabindex="-1"><a class="header-anchor" href="#_3-8-事务操作" aria-hidden="true">#</a> 3.8 事务操作</h3><table><thead><tr><th>Mongoose 方法</th><th>MongoDB 命令</th><th>说明</th></tr></thead><tbody><tr><td><code>mongoose.startSession()</code></td><td><code>startSession</code></td><td>开启会话</td></tr><tr><td><code>session.startTransaction()</code></td><td><code>startTransaction</code></td><td>开启事务</td></tr><tr><td><code>session.commitTransaction()</code></td><td><code>commitTransaction</code></td><td>提交事务</td></tr><tr><td><code>session.abortTransaction()</code></td><td><code>abortTransaction</code></td><td>回滚事务</td></tr></tbody></table><h3 id="_3-9-常用查询修饰符" tabindex="-1"><a class="header-anchor" href="#_3-9-常用查询修饰符" aria-hidden="true">#</a> 3.9 常用查询修饰符</h3><table><thead><tr><th>Mongoose 修饰符</th><th>MongoDB 行为</th><th>说明</th></tr></thead><tbody><tr><td><code>.sort({ field: 1 })</code></td><td><code>sort: { field: 1 }</code></td><td>排序</td></tr><tr><td><code>.limit(n)</code></td><td><code>limit: n</code></td><td>限制数量</td></tr><tr><td><code>.skip(n)</code></td><td><code>skip: n</code></td><td>跳过文档</td></tr><tr><td><code>.select(fields)</code></td><td><code>projection: fields</code></td><td>投影</td></tr><tr><td><code>.populate(path)</code></td><td><code>$lookup</code> + 额外查询</td><td>关联查询</td></tr><tr><td><code>.lean()</code></td><td>跳过 Document 转换</td><td>返回原始对象</td></tr><tr><td><code>.explain()</code></td><td><code>explain</code></td><td>执行计划</td></tr></tbody></table><h3 id="_3-10-更新操作符映射" tabindex="-1"><a class="header-anchor" href="#_3-10-更新操作符映射" aria-hidden="true">#</a> 3.10 更新操作符映射</h3><table><thead><tr><th>Mongoose 方法</th><th>MongoDB 更新操作符</th></tr></thead><tbody><tr><td><code>$set</code></td><td><code>doc.field = value</code></td></tr><tr><td><code>$unset</code></td><td><code>doc.field = undefined</code> (配合 <code>unset: true</code>)</td></tr><tr><td><code>$inc</code></td><td><code>doc.increment()</code></td></tr><tr><td><code>$push</code></td><td><code>doc.$push()</code></td></tr><tr><td><code>$pull</code></td><td><code>doc.$pull()</code></td></tr><tr><td><code>$addToSet</code></td><td><code>doc.addToSet()</code></td></tr></tbody></table><h2 id="四、实战-追踪-mongoose-到-mongodb-的转换" tabindex="-1"><a class="header-anchor" href="#四、实战-追踪-mongoose-到-mongodb-的转换" aria-hidden="true">#</a> 四、实战：追踪 Mongoose 到 MongoDB 的转换</h2><h3 id="_4-1-使用-debug-模式" tabindex="-1"><a class="header-anchor" href="#_4-1-使用-debug-模式" aria-hidden="true">#</a> 4.1 使用 debug 模式</h3><p>开启 Mongoose 的 debug 模式可以看到所有发送到 MongoDB 的命令：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>mongoose<span class="token punctuation">.</span><span class="token function">set</span><span class="token punctuation">(</span><span class="token string">&#39;debug&#39;</span><span class="token punctuation">,</span> <span class="token boolean">true</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// 或者只监听特定连接</span>
mongoose<span class="token punctuation">.</span>connection<span class="token punctuation">.</span><span class="token function">on</span><span class="token punctuation">(</span><span class="token string">&#39;debug&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">(</span><span class="token parameter">collectionName<span class="token punctuation">,</span> method<span class="token punctuation">,</span> query<span class="token punctuation">,</span> doc</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>collectionName<span class="token punctuation">,</span> method<span class="token punctuation">,</span> query<span class="token punctuation">,</span> doc<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>输出示例：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>users find { name: &#39;zhaoyifan&#39; } {}
users updateOne { _id: ObjectId(&quot;...&quot;) } { &#39;$set&#39;: { age: 25 } }
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_4-2-查看原生-mongodb-driver-调用" tabindex="-1"><a class="header-anchor" href="#_4-2-查看原生-mongodb-driver-调用" aria-hidden="true">#</a> 4.2 查看原生 MongoDB Driver 调用</h3><p>可以通过以下方式查看底层的 MongoDB 操作：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> mongoose <span class="token operator">=</span> <span class="token function">require</span><span class="token punctuation">(</span><span class="token string">&#39;mongoose&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token keyword">const</span> mongodb <span class="token operator">=</span> <span class="token function">require</span><span class="token punctuation">(</span><span class="token string">&#39;mongodb&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

mongoose<span class="token punctuation">.</span><span class="token function">connect</span><span class="token punctuation">(</span><span class="token string">&#39;mongodb://localhost/test&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// 访问原生 collection</span>
<span class="token keyword">const</span> User <span class="token operator">=</span> mongoose<span class="token punctuation">.</span><span class="token function">model</span><span class="token punctuation">(</span><span class="token string">&#39;User&#39;</span><span class="token punctuation">,</span> <span class="token keyword">new</span> <span class="token class-name">mongoose<span class="token punctuation">.</span>Schema</span><span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token literal-property property">name</span><span class="token operator">:</span> String <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
User<span class="token punctuation">.</span>collection<span class="token punctuation">.</span><span class="token function">find</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">toArray</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token parameter">err<span class="token punctuation">,</span> docs</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>docs<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_4-3-对比性能" tabindex="-1"><a class="header-anchor" href="#_4-3-对比性能" aria-hidden="true">#</a> 4.3 对比性能</h3><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// Mongoose（有 schema 转换开销）</span>
<span class="token keyword">const</span> users <span class="token operator">=</span> <span class="token keyword">await</span> User<span class="token punctuation">.</span><span class="token function">find</span><span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&#39;zhaoyifan&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// 原生 Driver（更直接）</span>
<span class="token keyword">const</span> users <span class="token operator">=</span> <span class="token keyword">await</span> db<span class="token punctuation">.</span><span class="token function">collection</span><span class="token punctuation">(</span><span class="token string">&#39;users&#39;</span><span class="token punctuation">)</span>
  <span class="token punctuation">.</span><span class="token function">find</span><span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&#39;zhaoyifan&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>
  <span class="token punctuation">.</span><span class="token function">toArray</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// 性能优化：使用 lean()</span>
<span class="token keyword">const</span> users <span class="token operator">=</span> <span class="token keyword">await</span> User<span class="token punctuation">.</span><span class="token function">find</span><span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&#39;zhaoyifan&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">lean</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="五、总结" tabindex="-1"><a class="header-anchor" href="#五、总结" aria-hidden="true">#</a> 五、总结</h2><ol><li><p><strong>Mongoose 是封装层</strong>：它在 MongoDB Driver 之上提供了更友好的 API，但不改变底层数据库行为</p></li><li><p><strong>执行流程</strong>：Schema 定义 → Model 创建 → 查询构建 → Driver 调用 → 结果转换</p></li><li><p><strong>方法映射</strong>：Mongoose 的绝大多数方法都有对应的 MongoDB 命令，理解这个映射有助于：</p><ul><li>编写更高效的查询</li><li>排查性能问题</li><li>在必要时绕过 Mongoose 使用原生 Driver</li></ul></li><li><p><strong>性能考量</strong>：Mongoose 提供了便捷性，但也带来了额外的开销。在高性能场景下，可以考虑：</p><ul><li>使用 <code>.lean()</code> 跳过 Document 转换</li><li>直接使用 MongoDB Driver</li><li>合理使用索引和投影</li></ul></li></ol><p>理解 Mongoose 的实现原理，可以帮助我们更好地使用它，写出更高质量的代码。</p><h2 id="参考资料" tabindex="-1"><a class="header-anchor" href="#参考资料" aria-hidden="true">#</a> 参考资料</h2>`,75),p={href:"https://mongoosejs.com/",target:"_blank",rel:"noopener noreferrer"},u={href:"https://mongodb.github.io/node-mongodb-native/",target:"_blank",rel:"noopener noreferrer"},h={href:"https://github.com/Automattic/mongoose",target:"_blank",rel:"noopener noreferrer"};function v(m,b){const e=d("ExternalLinkIcon");return o(),i("div",null,[l,n("ul",null,[n("li",null,[n("a",p,[t("Mongoose 官方文档"),a(e)])]),n("li",null,[n("a",u,[t("MongoDB Node.js Driver 文档"),a(e)])]),n("li",null,[n("a",h,[t("Mongoose 源码"),a(e)])])])])}const g=s(r,[["render",v],["__file","0304.html.vue"]]);export{g as default};
